#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
long long Z,n,T,tt,bb,l1,l2;
struct mofa{
    long long t,b;
}k[N],f[N];
bool v;
bool cmp1(mofa x,mofa y){return x.t<y.t;}
bool cmp2(mofa x,mofa y){return x.t+x.b>y.t+y.b;}
int main(){
    cin>>Z;
    while(Z--){
        v=1,l1=0,l2=0;
        cin>>n>>T;
        for(int i=1;i<=n;i++){
            cin>>tt>>bb;
            if(bb>=0){l1++;k[l1].t=tt,k[l1].b=bb;}
            else{l2++;f[l2].t=tt,f[l2].b=bb;}
        }
        sort(k+1,k+l1+1,cmp1);
        sort(f+1,f+l2+1,cmp2);
        for(int i=1;i<=l1;i++){
            if(T>k[i].t)T+=k[i].b;
            else v=0;
        }
        if(v){
            for(int i=1;i<=l2;i++){
                if(T>f[i].t&&T+f[i].b>0)T+=f[i].b;
                else v=0;
            }
        }

        if(v)cout<<"+1s\n";
        else cout<<"-1s\n";
    }


    return 0;
}
